
--ROLLING RETENTION:
--for each cohort and each month since acquisition, what % of users are still active at or
--after that month. 
--among the original cohort, what % bought in month N or later at least once?

WITH rr_base AS (
    SELECT
        csum.customerkey,
        csum.cohort_month,
        DATE_TRUNC('month', oe.orderdate) AS order_month
    FROM customer_summary csum
    JOIN order_enriched oe
        ON csum.customerkey = oe.customerkey
),


rr_index AS (
    SELECT DISTINCT
        customerkey,
        cohort_month,
        (
            DATE_PART('year', order_month) * 12 +
            DATE_PART('month', order_month)
        ) -
        (
            DATE_PART('year', cohort_month) * 12 +
            DATE_PART('month', cohort_month)
        ) AS months_number
    FROM rr_base
),


rr_max_month AS (
    SELECT
        cohort_month,
        MAX(months_number) AS max_months_number
    FROM rr_index
    GROUP BY cohort_month
),


rr_grid AS (
    SELECT
        cohort_month,
        generate_series(0, max_months_number::int) AS months_number
    FROM rr_max_month
),



--rolling retained users (numerator of my retention %):
rr_retention AS (
    SELECT
        rrg.cohort_month,
        rrg.months_number,
        COUNT(DISTINCT rri.customerkey) AS retained_customers
    FROM rr_grid rrg
    LEFT JOIN rr_index rri
        ON rrg.cohort_month = rri.cohort_month
       AND rri.months_number >= rrg.months_number
    GROUP BY
        rrg.cohort_month,
        rrg.months_number
),


--number of users per cohort. the denominator of my retention %
rr_size AS (
    SELECT
        cohort_month,
        COUNT(*) AS cohort_size
    FROM customer_summary
    WHERE first_purchase_date IS NOT NULL
    GROUP BY cohort_month
)


SELECT
    rrr.cohort_month,
    rrr.months_number,
    rrr.retained_customers,
    rrs.cohort_size,
    ROUND(rrr.retained_customers * 100.0 / rrs.cohort_size, 2) AS rolling_retention_rate_pct
FROM rr_retention rrr
JOIN rr_size rrs
    ON rrr.cohort_month = rrs.cohort_month
ORDER BY
    rrr.cohort_month,
    rrr.months_number;


